// payment.sql.go — hand-written sqlc query implementations for payment-svc S2-E-02.
//
// NOTE: These functions would normally be generated by `sqlc generate` from
// payment.sql. They are written by hand because sqlc is not available in the
// sandbox. Run `make generate` to regenerate, then delete this file.
//
// Each function follows the exact same pattern as the auto-generated system.sql.go:
// embed the SQL constant, call QueryRow/Query, scan fields in SELECT column order.

package sqlc

import (
	"context"

	"github.com/jackc/pgx/v5/pgtype"
)

