const createInvoice = `-- name: CreateInvoice :one
INSERT INTO payment.invoices (
    booking_id,
    amount_total,
    rounding_adjustment_idr,
    currency,
    fx_snapshot,
    status,
    paid_amount
) VALUES (
    $1, $2, $3, $4, $5, $6, $7
)
RETURNING id, booking_id, amount_total, rounding_adjustment_idr, currency, fx_snapshot, status, paid_amount, created_at, updated_at`

type CreateInvoiceParams struct {
	BookingID             pgtype.UUID    `json:"booking_id"`
	AmountTotal           pgtype.Numeric `json:"amount_total"`
	RoundingAdjustmentIdr pgtype.Numeric `json:"rounding_adjustment_idr"`
	Currency              string         `json:"currency"`
	FxSnapshot            []byte         `json:"fx_snapshot"`
	Status                string         `json:"status"`
	PaidAmount            pgtype.Numeric `json:"paid_amount"`
}

func (q *Queries) CreateInvoice(ctx context.Context, arg CreateInvoiceParams) (Invoice, error) {
	row := q.db.QueryRow(ctx, createInvoice,
		arg.BookingID,
		arg.AmountTotal,
		arg.RoundingAdjustmentIdr,
		arg.Currency,
		arg.FxSnapshot,
		arg.Status,
		arg.PaidAmount,
	)
	var i Invoice
	err := row.Scan(
		&i.ID,
		&i.BookingID,
		&i.AmountTotal,
		&i.RoundingAdjustmentIdr,
		&i.Currency,
		&i.FxSnapshot,
		&i.Status,
		&i.PaidAmount,
		&i.CreatedAt,
		&i.UpdatedAt,
	)
	return i, err
}

