const listUnpaidInvoicesWithActiveVA = `-- name: ListUnpaidInvoicesWithActiveVA :many
SELECT DISTINCT ON (i.id)
    i.id, i.booking_id, i.amount_total, i.rounding_adjustment_idr, i.currency,
    i.fx_snapshot, i.status, i.paid_amount, i.created_at, i.updated_at
FROM payment.invoices i
JOIN payment.virtual_accounts va ON va.invoice_id = i.id
WHERE i.status IN ('unpaid', 'partially_paid')
  AND va.status = 'active'
  AND va.expires_at > NOW()
ORDER BY i.id, i.created_at ASC`

func (q *Queries) ListUnpaidInvoicesWithActiveVA(ctx context.Context) ([]Invoice, error) {
	rows, err := q.db.Query(ctx, listUnpaidInvoicesWithActiveVA)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var items []Invoice
	for rows.Next() {
		var i Invoice
		if err := rows.Scan(
			&i.ID,
			&i.BookingID,
			&i.AmountTotal,
			&i.RoundingAdjustmentIdr,
			&i.Currency,
			&i.FxSnapshot,
			&i.Status,
			&i.PaidAmount,
			&i.CreatedAt,
			&i.UpdatedAt,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	return items, rows.Err()
}

